queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?themename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasThemes ?child ; p:hasSummer_Camps ?parent . } GROUP BY ?child }
  ?child p:themeName ?themename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Summer_Camps } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?themename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasThemes ?child ; p:hasSummer_Camps ?parent . } GROUP BY ?child }
  ?child p:themeName ?themename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Summer_Camps } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?campname ?themename WHERE {
  ?summer_camp_themes a :Summer_Camp_Themes .
  ?themes a :Themes .
  ?summer_camp_themes p:hasThemes ?themes .
  ?summer_camps a :Summer_Camps .
  ?summer_camp_themes p:hasSummer_Camps ?summer_camps .
  ?summer_camps p:campName ?campname .
  ?themes p:themeName ?themename .
} }
}
